@@ -114,15 +114,18 @@
 struct radix_node_head *rt_tables[AF_MAX+1];

 int    NewTree = 0;
+int    total = 0;

 static struct sockaddr *kgetsa __P((struct sockaddr *));
 static void p_tree __P((struct radix_node *));
+static void c_tree __P((struct radix_node *));
 static void p_rtnode __P((void));
