@@ -877,4 +880,89 @@
                        *p += ('A' - 'a');
                        break;
                }
+}
+
+void
+routecount(rtree)
+        u_long rtree;
+{
+        struct radix_node_head *rnh, head;
+        int i;
+
+        printf("Routing tables\n");
+
+        if (Aflag == 0 && NewTree)
+                ntreestuff();
+        else {
+                if (rtree == 0) {
+                        printf("rt_tables: symbol not in namelist\n");
+                        return;
+                }
+
+                kget(rtree, rt_tables);
+                for (i = 0; i <= AF_MAX; i++) {
+                        if ((rnh = rt_tables[i]) == 0)
+                                continue;
+                        kget(rnh, head);
+                        if (i == AF_UNSPEC) {
+                                if (Aflag && af == 0) {
+                                        printf("Netmasks:\n");
+                                        c_tree(head.rnh_treetop);
+                                }
+                        } else if (af == AF_UNSPEC || af == i) {
+                                pr_family(i);
+                                do_rtent = 1;
+                               total=0;
+                                c_tree(head.rnh_treetop);
+                               printf("%d Routes\n",total);
+                        }
+                }
+        }
+}
+
+static void
+c_tree(rn)
+        struct radix_node *rn;
+{
+
+again:
+        kget(rn, rnode);
+        if (rnode.rn_b < 0) {
+                if (Aflag)
+                        printf("%-8.8lx ", (u_long)rn);
+                if (rnode.rn_flags & RNF_ROOT) {
+                        if (Aflag)
+                                printf("(root node)%s",
+                                    rnode.rn_dupedkey ? " =>\n" :
"\n");
+                } else if (do_rtent) {
+                        kget(rn, rtentry);
+                        c_rtentry(&rtentry);
+                        if (Aflag)
+                                p_rtnode();
+                } else {
+                        p_sockaddr(kgetsa((struct sockaddr
*)rnode.rn_key),
+                                   NULL, 0, 44);
+                        putchar('\n');
+                }
+                if ((rn = rnode.rn_dupedkey))
+                        goto again;
+        } else {
+                if (Aflag && do_rtent) {
+                        printf("%-8.8lx ", (u_long)rn);
+                        p_rtnode();
+                }
+                rn = rnode.rn_r;
+                c_tree(rnode.rn_l);
+                c_tree(rn);
+        }
+}
+
+
+static void
+c_rtentry(rt)
+       register struct rtentry *rt;
+{
+                       if (!(rt->rt_parent && !aflag)) {
+                       ++total;
+                       }
 }
